44	template <class... Args>
45	struct Copy_Atom;
46	
47	template <class CopyOperation, class CopyInternalType>
48	struct Copy_Atom<CopyOperation, CopyInternalType> : Copy_Atom<Copy_Traits<CopyOperation>, CopyInternalType>
49	{};
50	
51	template <class... Args, class CopyInternalType>
52	struct Copy_Atom<Copy_Traits<Args...>, CopyInternalType>
53	  : Copy_Traits<Args...>
54	{
55	  using Traits = Copy_Traits<Args...>;
56	
57	  // Bit and Thr layouts from the Copy_Traits
58	  using ThrID        = typename Traits::ThrID;
59	  using BitLayoutSrc = typename Traits::SrcLayout;
60	  using BitLayoutDst = typename Traits::DstLayout;
61	  using BitLayoutRef = typename Traits::RefLayout;
62	
63	  using ValType = CopyInternalType;
64	
65	  using ValLayoutSrc = decltype(recast_layout<uint1_t, ValType>(BitLayoutSrc{}));
66	  using ValLayoutDst = decltype(recast_layout<uint1_t, ValType>(BitLayoutDst{}));
67	  using ValLayoutRef = decltype(recast_layout<uint1_t, ValType>(BitLayoutRef{}));
68	
69	  CUTE_STATIC_ASSERT_V(size<0>(ValLayoutSrc{}) == size(ThrID{}), "CopyOperation is not valid for Src of ValType.");
70	  CUTE_STATIC_ASSERT_V(size<0>(ValLayoutDst{}) == size(ThrID{}), "CopyOperation is not valid for Dst of ValType.");
71	  CUTE_STATIC_ASSERT_V(size<0>(ValLayoutRef{}) == size(ThrID{}), "CopyOperation is not valid for Ref of ValType.");
72	
73	  static constexpr int NumValSrc = size<1>(ValLayoutSrc{});
74	  static constexpr int NumValDst = size<1>(ValLayoutDst{});
75	
76	  // Additional Trait parameters/transformations
77	  template <class... TraitsArgs>
78	  CUTE_HOST_DEVICE
79	  auto
80	  with(TraitsArgs&&... args) const {
81	    auto traits = Traits::with(static_cast<TraitsArgs&&>(args)...);
82	    return Copy_Atom<decltype(traits), CopyInternalType>{traits};
83	  }
84	
85	  //
86	  // Tensor call interfaces
87	  //
88	
89	  // Check and call instruction, or recurse
90	  template <class SEngine, class SLayout,
91	            class DEngine, class DLayout>
92	  CUTE_HOST_DEVICE
93	  void
94	  call(Tensor<SEngine,SLayout> const& src,
95	       Tensor<DEngine,DLayout>      & dst) const
96	  {
97	    static_assert(SLayout::rank == 1, "Expected rank-1 src tensor");
98	    static_assert(DLayout::rank == 1, "Expected rank-1 dst tensor");
99	
100	    if constexpr (is_constant<NumValSrc, decltype(size(src))>::value ||
101	                  is_constant<NumValDst, decltype(size(dst))>::value) {
102	      // Dispatch to unpack to execute instruction
103	      return copy_unpack(static_cast<Traits const&>(*this), src, dst);
104	    } else if constexpr (is_tuple<decltype(shape(src))>::value &&
105	                         is_tuple<decltype(shape(dst))>::value) {
106	      // If the size of the src/dst doesn't match the instruction,
107	      //   recurse this rank-1 layout by peeling off the mode
108	      //   ((A,B,C,...)) -> (A,B,C,...)
109	      return copy(*this, tensor<0>(src), tensor<0>(dst));
110	    } else {
111	      static_assert(dependent_false<SEngine>,
112	                    "CopyAtom: Src/Dst partitioning does not match the instruction requirement.");
113	    }
114	  }
115	
116	  // Accept mutable temporaries
117	  template <class SEngine, class SLayout,
118	            class DEngine, class DLayout>
119	  CUTE_HOST_DEVICE
120	  void
121	  call(Tensor<SEngine,SLayout> const& src,
122	       Tensor<DEngine,DLayout>     && dst) const
123	  {
124	    return call(src, dst);
125	  }
126	
127	  // Check and call instruction, or recurse
128	  template <class PEngine, class PLayout,
129	            class SEngine, class SLayout,
130	            class DEngine, class DLayout>
131	  CUTE_HOST_DEVICE
132	  void
133	  call(Tensor<PEngine,PLayout> const& prd,
134	       Tensor<SEngine,SLayout> const& src,
135	       Tensor<DEngine,DLayout>      & dst) const
136	  {
137	    static_assert(PLayout::rank == 1, "Expected rank-1 prd tensor");
138	    static_assert(SLayout::rank == 1, "Expected rank-1 src tensor");
139	    static_assert(DLayout::rank == 1, "Expected rank-1 dst tensor");
140	
141	    if constexpr (is_constant<NumValSrc, decltype(size(src))>::value ||
142	                  is_constant<NumValDst, decltype(size(dst))>::value) {
143	      // Dispatch to unpack to execute instruction
144	      Traits const& traits = static_cast<Traits const&>(*this);
145	      auto has_with_bool = cute::is_valid([](auto t)->void_t<decltype(t.with(true))>{}, traits);
146	      if constexpr (has_with_bool) {
147	        copy_unpack(traits.with(prd(Int<0>{})), src, dst);
148	      } else {
149	        if (prd(Int<0>{})) { copy_unpack(traits, src, dst); }
150	      }
151	    } else if constexpr (is_tuple<decltype(shape(prd))>::value &&
152	                         is_tuple<decltype(shape(src))>::value &&
153	                         is_tuple<decltype(shape(dst))>::value) {
154	      // If the size of the src/dst doesn't match the instruction,
155	      //   recurse this rank-1 layout by peeling off the mode
156	      //   ((A,B,C,...)) -> (A,B,C,...)
157	      return copy_if(*this, tensor<0>(prd), tensor<0>(src), tensor<0>(dst));
158	    } else {
159	      static_assert(dependent_false<SEngine>,
160	                    "CopyAtom: Src/Dst partitioning does not match the instruction requirement.");
161	    }
162	  }
163	
164	  // Accept mutable temporaries
165	  template <class PEngine, class PLayout,
166	            class SEngine, class SLayout,
167	            class DEngine, class DLayout>
168	  CUTE_HOST_DEVICE
169	  void
170	  call(Tensor<PEngine,PLayout> const& prd,
171	       Tensor<SEngine,SLayout> const& src,
172	       Tensor<DEngine,DLayout>     && dst) const
173	  {
174	    return call(prd, src, dst);
175	  }
176	};
