178	//
179	// A tiling of copy atoms
180	//
181	
182	template <class TiledCopy, class ThrIdx>
183	struct ThrCopy;
184	
185	template <class Copy_Atom,
186	          class LayoutCopy_TV,  // (tid,vid) -> coord   [Need not be 2D...]
187	          class ShapeTiler_MN>  // coord space
188	struct TiledCopy : Copy_Atom
189	{
190	  // Layout information from the CopyAtom
191	  using AtomThrID     = typename Copy_Atom::ThrID;        // thrid -> thr_idx
192	  using AtomLayoutSrc = typename Copy_Atom::ValLayoutSrc; // (thr,val) -> offset
193	  using AtomLayoutDst = typename Copy_Atom::ValLayoutDst; // (thr,val) -> offset
194	  using AtomLayoutRef = typename Copy_Atom::ValLayoutRef; // (thr,val) -> offset
195	
196	  using AtomNumThr = decltype(size<0>(AtomLayoutRef{}));
197	  using AtomNumVal = decltype(size<1>(AtomLayoutRef{}));
198	
199	  // Layout information for the TiledCopy
200	  using Tiler_MN       = ShapeTiler_MN;
201	  using TiledLayout_TV = LayoutCopy_TV;
202	  using TiledNumThr    = decltype(size<0>(TiledLayout_TV{}));
203	  using TiledNumVal    = decltype(size<1>(TiledLayout_TV{}));
204	
205	  CUTE_STATIC_ASSERT_V(TiledNumThr{} % AtomNumThr{} == Int<0>{}, "TiledCopy uses too few thrs for selected CopyAtom");
206	  CUTE_STATIC_ASSERT_V(TiledNumVal{} % AtomNumVal{} == Int<0>{}, "TiledCopy uses too few vals for selected CopyAtom");
207	
208	  // Tile a tensor or a layout from shape
209	  //   (M,N,...)
210	  // to shape
211	  //   (Thr,(FrgV,FrgX),(RestM,RestN,...))
212	  // where
213	  //   Thr:   The logical threads within the tiled copy.
214	  //   FrgV:  The values local to a COPY_ATOM Src.
215	  //   FrgX:  The values tiled across COPY_ATOMs Src.
216	  //   RestM: The values tiled in M.
217	  //   RestN: The values tiled in N.
218	  template <class STensor>
219	  CUTE_HOST_DEVICE constexpr static
220	  auto
221	  tidfrg_S(STensor&& stensor)
222	  {
223	    CUTE_STATIC_ASSERT_V(rank(stensor) >= rank(Tiler_MN{}), "Rank of tensor to be partitioned too small.");
224	
225	    // Tile the stensor and compute the (src-thr, src-val) -> (ref-thr, ref-val) layout
226	    return tile2thrfrg(zipped_divide(stensor,Tiler_MN{}), right_inverse(AtomLayoutRef{}).compose(AtomLayoutSrc{}));
227	  }
228	
229	  // Tile a tensor or a layout from shape
230	  //   (M,N,...)
231	  // to shape
232	  //   (Thr,(FrgV,FrgX),(RestM,RestN,...))
233	  // where
234	  //   Thr:   The logical threads within the tiled copy.
235	  //   FrgV:  The values local to a COPY_ATOM Dst.
236	  //   FrgX:  The values tiled across COPY_ATOMs Dst.
237	  //   RestM: The values tiled in M.
238	  //   RestN: The values tiled in N.
239	  template <class DTensor>
240	  CUTE_HOST_DEVICE constexpr static
241	  auto
242	  tidfrg_D(DTensor&& dtensor)
243	  {
244	    CUTE_STATIC_ASSERT_V(rank(dtensor) >= rank(Tiler_MN{}), "Rank of tensor to be partitioned too small.");
245	
246	    // Tile the dtensor and compute the (dst-thr, dst-val) -> (ref-thr, ref-val) layout
247	    return tile2thrfrg(zipped_divide(dtensor,Tiler_MN{}), right_inverse(AtomLayoutRef{}).compose(AtomLayoutDst{}));
248	  }
249	
250	  // Tile a tensor or a layout from shape
251	  //   ((TileM,TileN,...), (RestM,RestN,...))
252	  // to shape
253	  //   (Thr,(FrgV,FrgX),(RestM,RestN,...))
254	  template <class Tensor, class Ref2TrgLayout>
255	  CUTE_HOST_DEVICE constexpr static
256	  auto
257	  tile2thrfrg(Tensor&& tensor, Ref2TrgLayout const& ref2trg)
258	  {
259	    // Take the thrs/vals that the atom is interested in
260	    // NOTE: Assumes the AtomNumThr are contiguous and identity within TiledThrID
261	    auto atom_layout_TV = zipped_divide(TiledLayout_TV{}, make_shape(AtomNumThr{}, AtomNumVal{}));
262	    // ((atom_tid,atom_val),(rest_tid,rest_val)) -> (m,n)
263	
264	    // Transform to the trg layout
265	    auto trg_layout_TV = atom_layout_TV.compose(ref2trg, _);
266	    // ((trg_tid,trg_val),(rest_tid,rest_val)) -> (m,n)
267	
268	    // Transform the thrs mode from thrid to thr_idx
269	    // NOTE: Assumes the AtomNumThr are contiguous and identity within TiledThrID
270	    auto thrval2mn = coalesce(zip(trg_layout_TV), Shape<_1,Shape<_1,_1>>{});
271	    // ((trg_tid,rest_tid),(trg_val,rest_val)) -> (m,n)
272	
273	    /// ==================
274	
275	    // Transform the tile mode
276	    auto tv_tensor = tensor.compose(thrval2mn, _);
277	    // ((thrid,val),(RestM,RestN,...))
278	
279	    // Unfold and return
280	    return tv_tensor(make_coord(_,_), _);
281	  }
282	
283	  // retile_S and retile_D assume they are working with the reference layout -- they are the same
284	  template <class Tensor>
285	  CUTE_HOST_DEVICE constexpr static
286	  auto
287	  retile(Tensor&& tensor)
288	  {
289	    constexpr int R = remove_cvref_t<Tensor>::rank;
290	    // Assert that AtomLayoutSrc|Dst is identity so we can skip the Ref transformation
291	
292	    // Assume the first size<0>(tensor) elements are the first val_ids in TiledLayout_TV.
293	    // Then, we only need the shape+layout of those size<0>(tensor) elements in TiledLayout_TV
294	    //   and that shape is what we gather from the other modes of tensor
295	
296	    auto V = size<0>(tensor);
297	
298	    auto frg_layout_mn = upcast<TiledNumThr{} * V>(right_inverse(TiledLayout_TV{}).with_shape(shape(Tiler_MN{})));
299	    // (m,n) -> v_idx -- The shape and order of the V inside of TiledLayout_TV
300	
301	    auto frg_layout_v = zipped_divide(logical_product(make_layout(V), right_inverse(frg_layout_mn)), make_layout(AtomNumVal{}));
302	    // (atom_vals,rest_vals) -> (v,m,n)
303	
304	    /// =======
305	
306	    // Tile the tensor for TileFrg
307	    auto t_tensor = zipped_divide(tensor, prepend(product_each(shape(frg_layout_mn)), V));
308	    // ((TileV,TileM,TileN,...),(1,RestM,RestN,...))
309	
310	    // Transform the tile mode
311	    auto v_tensor = t_tensor.compose(frg_layout_v, _);
312	    // ((atom_vals,rest_vals),(1,RM,RN,...))
313	
314	    // Unfold and return
315	    return v_tensor(_, append<R>(Int<0>{},_));
316	  }
317	
318	  CUTE_HOST_DEVICE constexpr static
319	  auto
320	  get_layoutS_TV()
321	  {
322	    // (M,N) -> (M,N)
323	    auto ref_S = make_layout(make_shape(shape(Tiler_MN{}), Int<1>{}));
324	    // (thr_idx,val_idx) -> (M,N)
325	    return tile2thrfrg(ref_S, right_inverse(AtomLayoutRef{}).compose(AtomLayoutSrc{}))(_,_,Int<0>{});
326	  }
327	
328	  CUTE_HOST_DEVICE constexpr static
329	  auto
330	  get_layoutD_TV()
331	  {
332	    // (M,N) -> (M,N)
333	    auto ref_D = make_layout(make_shape(shape(Tiler_MN{}), Int<1>{}));
334	    // (thr_idx,val_idx) -> (M,N)
335	    return tile2thrfrg(ref_D, right_inverse(AtomLayoutRef{}).compose(AtomLayoutDst{}))(_,_,Int<0>{});
336	  }
337	
338	  template <class ThrIdx,
339	            __CUTE_REQUIRES(is_integral<ThrIdx>::value)>
340	  CUTE_HOST_DEVICE static
341	  auto
342	  get_slice(ThrIdx const& thr_idx)
343	  {
344	    return ThrCopy<TiledCopy, ThrIdx>(thr_idx);
345	  }
346	
347	  template <class ThrIdx,
348	            __CUTE_REQUIRES(is_integral<ThrIdx>::value)>
349	  CUTE_HOST_DEVICE  static
350	  auto
351	  get_thread_slice(ThrIdx const& thr_idx)
352	  {
353	    return get_slice(thr_idx);
354	  }
355	};
