357	template <class TiledCopy, class ThrIdx>
358	struct ThrCopy
359	{
360	  ThrIdx thr_idx_;
361	
362	  CUTE_HOST_DEVICE
363	  ThrCopy(ThrIdx const& thr_idx) : thr_idx_(thr_idx) {}
364	
365	  template <class STensor>
366	  CUTE_HOST_DEVICE
367	  auto
368	  partition_S(STensor&& stensor) const {
369	    //static_assert(sizeof(typename remove_cvref_t<STensor>::value_type) == sizeof(typename TiledCopy::ValType),
370	    //              "Expected ValType for tiling SrcTensor.");
371	    auto thr_tensor = make_tensor(static_cast<STensor&&>(stensor).data(), TiledCopy::tidfrg_S(stensor.layout()));
372	    return thr_tensor(thr_idx_, _, repeat<rank_v<STensor>>(_));
373	  }
374	
375	  template <class DTensor>
376	  CUTE_HOST_DEVICE
377	  auto
378	  partition_D(DTensor&& dtensor) const {
379	    //static_assert(sizeof(typename remove_cvref_t<DTensor>::value_type) == sizeof(typename TiledCopy::ValType),
380	    //              "Expected ValType for tiling DstTensor.");
381	    auto thr_tensor = make_tensor(static_cast<DTensor&&>(dtensor).data(), TiledCopy::tidfrg_D(dtensor.layout()));
382	    return thr_tensor(thr_idx_, _, repeat<rank_v<DTensor>>(_));
383	  }
384	
385	  template <class STensor>
386	  CUTE_HOST_DEVICE static
387	  auto
388	  retile_S(STensor&& stensor) {
389	    // static_assert(sizeof(typename remove_cvref_t<STensor>::value_type) == sizeof(typename TiledCopy::ValType),
390	    //               "Expected ValType for tiling SrcTensor.");
391	    return make_tensor(static_cast<STensor&&>(stensor).data(), TiledCopy::retile(stensor.layout()));
392	  }
393	
394	  template <class DTensor>
395	  CUTE_HOST_DEVICE static
396	  auto
397	  retile_D(DTensor&& dtensor) {
398	    // static_assert(sizeof(typename remove_cvref_t<DTensor>::value_type) == sizeof(typename TiledCopy::ValType),
399	    //               "Expected ValType for tiling DstTensor.");
400	    return make_tensor(static_cast<DTensor&&>(dtensor).data(), TiledCopy::retile(dtensor.layout()));
401	  }
402	};
403	
404	
405	template <class... Args,
406	          class LayoutCopy_TV,
407	          class Tiler>
408	CUTE_HOST_DEVICE
409	auto constexpr
410	make_tiled_copy_impl(Copy_Atom<Args...> const& atom,
411	                     LayoutCopy_TV      const&,
412	                     Tiler              const&)
413	{
414	  return TiledCopy<Copy_Atom<Args...>, LayoutCopy_TV, Tiler>{atom};
415	}
416	
417	//
418	// These tile the Copy_Atom as a whole
419	//
420	
421	template <class... CArgs, class... MArgs>
422	CUTE_HOST_DEVICE
423	auto constexpr
424	make_tiled_copy_A(Copy_Atom<CArgs...> const& copy_atom,
425	                  TiledMMA<MArgs...>  const& mma)
426	{
427	  return make_tiled_copy_impl(copy_atom, mma.get_layoutA_TV(), make_shape(tile_size<0>(mma),tile_size<2>(mma)));
428	}
