430	template <class... CArgs, class... MArgs>
431	CUTE_HOST_DEVICE
432	auto constexpr
433	make_tiled_copy_B(Copy_Atom<CArgs...> const& copy_atom,
434	                  TiledMMA<MArgs...>  const& mma)
435	{
436	  return make_tiled_copy_impl(copy_atom, mma.get_layoutB_TV(), make_shape(tile_size<1>(mma),tile_size<2>(mma)));
437	}
438	
439	template <class... CArgs, class... MArgs>
440	CUTE_HOST_DEVICE
441	auto
442	make_tiled_copy_C(Copy_Atom<CArgs...> const& copy_atom,
443	                  TiledMMA<MArgs...>  const& mma)
444	{
445	  return make_tiled_copy_impl(copy_atom, mma.get_layoutC_TV(), make_shape(tile_size<0>(mma),tile_size<1>(mma)));
446	}
447	
448	// returns the smallest tiled copy that can retile LayoutC_TV
449	// for use with pipelined epilogues with subtiled stores
450	template <class... CArgs, class... MArgs>
451	CUTE_HOST_DEVICE
452	auto
453	make_tiled_copy_C_atom(Copy_Atom<CArgs...> const& copy_atom,
454	                       TiledMMA<MArgs...>  const& mma)
455	{
456	  // Truncate the V-layout to just the Copy_Atom, keep the V-order
457	  auto layoutC_TV = mma.get_layoutC_TV();
458	  auto copy_V     = Int<Copy_Atom<CArgs...>::NumValSrc>{};
459	  CUTE_STATIC_ASSERT_V(copy_V <= size<1>(layoutC_TV));
460	  auto layout_TV  = composition(layoutC_TV, make_layout(make_shape(size<0>(layoutC_TV), copy_V)));
461	
462	  // Recompute tiler and restride the TV layout for the new tiler
463	
464	  // Tiler -- Find the active elements in the MMA tensor and generate a tiler to extract them
465	  // Convert to the awkward by-mode tiler to preserve the modes of the tiled MMA
466	  auto mma_tiler = make_shape(tile_size<0>(mma),tile_size<1>(mma));
467	  auto mma_zeros = repeat_like(mma_tiler, Int<0>{});
468	
469	  auto tiler = transform(make_seq<rank(mma_tiler)>{}, [&](auto i) {
470	    return filter(composition(make_layout(mma_tiler, replace<i>(mma_zeros, Int<1>{})), layout_TV));
471	  });
472	
473	  // Layout_TV -- Find the (tid,vid) -> tile coord transformation
474	  // Apply the tiler to a reference and transform the codomain
475	  // tile_coord -> mma_coord
476	  auto tile2mma = composition(make_layout(mma_tiler), tiler);
477	
478	  // (tid,vid) -> tile_coord
479	  auto layout_tv = composition(left_inverse(tile2mma), layout_TV);
480	
481	  return make_tiled_copy_impl(copy_atom, layout_tv, tiler);
482	}
483	
484	/** Produce a TiledCopy from logical thread and values layouts.
485	 * The thread and value layouts map coordinates to thr_idx and val_idx.
486	 *    The product of these layouts is taken to produce the TV layout and the Tiler.
487	 * Useful when threads and values need very specific mappings onto coordinates
488	 *    in the target tensors.
489	 */
490	template <class... Args,
491	          class ThrLayout,
492	          class ValLayout = Layout<_1>>
493	CUTE_HOST_DEVICE
494	auto constexpr
495	make_tiled_copy(Copy_Atom<Args...> const& copy_atom,
496	                ThrLayout          const& thr_layout = {},     // (m,n) -> thr_idx
497	                ValLayout          const& val_layout = {})     // (m,n) -> val_idx
498	{
499	  // Take the raked_products to compute the Layout_MN
500	  // (M,N) -> (thr_idx, val_idx)
501	  auto layout_mn = raked_product(thr_layout, val_layout);
502	  // (thr_idx, val_idx) -> (M,N)
503	  auto layout_tv = right_inverse(layout_mn).with_shape(make_shape(size(thr_layout), size(val_layout)));
504	  // Tiler for extracting relevant elements
505	  // (M,N) -> tensor coord
506	  auto tiler = product_each(shape(layout_mn));
507	
508	#if 0
509	  print("thr_layout: "); print(thr_layout); print("\n");
510	  print("val_layout: "); print(val_layout); print("\n");
511	  print("layout_mn : "); print(layout_mn);  print("\n");
512	  print("layout_tv : "); print(layout_tv);  print("\n");
513	  print("tiler     : "); print(tiler);      print("\n");
514	#endif
515	
516	  return make_tiled_copy_impl(copy_atom, layout_tv, tiler);
517	}
518	
519	/** Produce a TiledCopy from thread and value offset maps.
520	 * The TV Layout maps threads and values to the codomain of the data_layout.
521	 * It is verified that the intended codomain is valid within data_layout.
522	 * Useful when threads and values don't care about owning specific coordinates, but
523	 *   care more about the vector-width and offsets between them.
524	 */
525	template <class... Args, class AtomTVLayout, class DataLayout>
526	CUTE_HOST_DEVICE constexpr
527	auto
528	make_cotiled_copy(Copy_Atom<Args...> const& copy_atom,
529	                  AtomTVLayout const& atom_tv_layout,   // atom (thr,val) -> data addr
530	                  DataLayout   const& data_layout)      // coord          -> data addr    The target layout
531	{
532	  static_assert(is_static<AtomTVLayout>::value);
533	  static_assert(is_static<DataLayout>::value);
534	
535	  // data addr -> data coord    Append 1:0 so off-the-ends get the stride-0
536	  auto inv_data_layout = make_layout(left_inverse(data_layout), Layout<_1,_0>{});
537	
538	  // (tid,vid) -> data_coord
539	  auto layout_tv_data = composition(inv_data_layout, atom_tv_layout);
540	
541	  // Check validity
542	  // Append 1:0 to data_layout so that OOB coordinates get the stride-0
543	  CUTE_STATIC_ASSERT_V(coalesce(composition(make_layout(data_layout, Layout<_1,_0>{}), layout<1>(layout_tv_data))) == coalesce(layout<1>(atom_tv_layout)),
544	                       "The memory pointed to by AtomTVLayout does not exist in the DataLayout.");
545	  //
546	  // Tiler -- Find the active elements in the DATA tensor and generate a tiler to extract them
547	  //
548	
549	  // Convert to the awkward by-mode tiler to preserve the modes of the tiled DATA
550	  auto flat_data_shape = product_each(shape(data_layout));
551	  auto flat_data_zeros = repeat<rank(flat_data_shape)>(Int<0>{});
552	
553	  auto tiler = transform(make_seq<rank(flat_data_shape)>{}, [&](auto i) {
554	    return filter(composition(make_layout(flat_data_shape, replace<i>(flat_data_zeros, Int<1>{})), layout_tv_data));
555	  });
556	
557	  //
558	  // Layout_TV -- Find the (tid,vid) -> tile coord transformation
559	  //
560	
561	  // Apply the tiler to a reference and transform the codomain
562	  // tile_coord -> data_coord
563	  auto tile2data = composition(make_layout(flat_data_shape), tiler);
564	
565	  // (tid,vid) -> tile_coord
566	  auto layout_tv = composition(left_inverse(tile2data), layout_tv_data);
567	  return make_tiled_copy_impl(copy_atom, layout_tv, tiler);
568	}
569	
570	// Make a TiledCopy out of the copy_atom that matches the Src-Layout of tiled_copy
571	template <class... Args,
572	          class TiledCopy>
573	CUTE_HOST_DEVICE
574	auto
575	make_tiled_copy_S(Copy_Atom<Args...> const& copy_atom,
576	                  TiledCopy          const& tiled_copy)
577	{
578	  return make_tiled_copy_impl(copy_atom, tiled_copy.get_layoutS_TV(), typename TiledCopy::Tiler_MN{});
579	}
580	
581	// Make a TiledCopy out of the copy_atom that matches the Dst-Layout of tiled_copy
582	template <class... Args,
583	          class TiledCopy>
584	CUTE_HOST_DEVICE
585	auto
586	make_tiled_copy_D(Copy_Atom<Args...> const& copy_atom,
587	                  TiledCopy          const& tiled_copy)
588	{
589	  return make_tiled_copy_impl(copy_atom, tiled_copy.get_layoutD_TV(), typename TiledCopy::Tiler_MN{});
590	}
591	
592	//
593	// Size
594	//
595	
596	// The logical size of a TileCopy
597	template <int... I, class... Args>
598	CUTE_HOST_DEVICE constexpr
599	auto
600	tile_size(TiledCopy<Args...> const&)
601	{
602	  return size<I...>(typename TiledCopy<Args...>::Tiler_MN{});
603	}
604	
605	// The number of threads involved in a TiledCopy
606	template <class... Args>
607	CUTE_HOST_DEVICE constexpr
608	auto
609	size(TiledCopy<Args...> const&)
610	{
611	  return typename TiledCopy<Args...>::TiledNumThr{};
612	}
613	
614	//
615	// Display utilities
616	//
617	
618	template <class... Args, class T>
619	CUTE_HOST_DEVICE
620	void
621	print(Copy_Atom<Copy_Traits<Args...>, T> const&)
622	{
623	  using Atom = Copy_Atom<Copy_Traits<Args...>, T>;
624	  print("Copy_Atom\n");
625	  print("  ThrID:        "); print(typename Atom::ThrID{});        print("\n");
626	  print("  ValLayoutSrc: "); print(typename Atom::ValLayoutSrc{}); print("\n");
627	  print("  ValLayoutDst: "); print(typename Atom::ValLayoutDst{}); print("\n");
628	  print("  ValLayoutRef: "); print(typename Atom::ValLayoutRef{}); print("\n");
629	  print("  ValueType:    "); print(sizeof_bits<typename Atom::ValType>::value); print("b\n");
630	}
631	
632	template <class Atom, class... Args>
633	CUTE_HOST_DEVICE
634	void
635	print(TiledCopy<Atom, Args...> const& copy, char const* pad = "")
636	{
637	  using Copy = TiledCopy<Atom, Args...>;
638	  print("TiledCopy\n");
639	  print("  Tiler_MN:       "); print(typename Copy::Tiler_MN{});       print("\n");
640	  print("  TiledLayout_TV: "); print(typename Copy::TiledLayout_TV{}); print("\n");
641	  print(static_cast<Atom const&>(copy));
642	}
643	
644	template <class TiledCopy, class ThrIdx>
645	CUTE_HOST_DEVICE
646	void
647	print(ThrCopy<TiledCopy, ThrIdx> const& thr_copy)
648	{
649	  print("ThrCopy\n");
650	  print("  ThrIdx: "); print(thr_copy.thr_idx_); print("\n");
651	  print(TiledCopy{});
652	}
653	
654	} // end namespace cute
